export interface Shop {
  id: string;
  name: string;
  lat: number;
  lng: number;
  city: string;
  country: string;
  type: "dispensary" | "coffeeshop" | "club" | "delivery";
  rating: number;
  reviewCount: number;
  isPremium: boolean;
  address: string;
  hours: string;
}

export type RegionFilter = "all" | "nearby" | "thailand" | "netherlands" | "usa" | "canada";

export function filterByRegion(shops: Shop[], region: RegionFilter): Shop[] {
  if (region === "all") return shops;
  const map: Record<string, string[]> = {
    thailand: ["Thailand"],
    netherlands: ["Netherlands"],
    usa: ["USA"],
    canada: ["Canada"],
  };
  const countries = map[region];
  if (!countries) return shops;
  return shops.filter(s => countries.includes(s.country));
}

